export function toMagicJson(n){const t={};for(let i in n)Object.prototype.hasOwnProperty.call(n,i)&&(n[i]?n[i]&&!Array.isArray(n[i])&&n[i].toLowerCase()==="true"?(t[i.replace("ViewModel.","")]=!0,t[i.replace("settings.","")]=!0):n[i]&&!Array.isArray(n[i])&&n[i].toLowerCase()==="false"?(t[i.replace("ViewModel.","")]=!1,t[i.replace("settings.","")]=!1):(t[i.replace("ViewModel.","")]=n[i],t[i.replace("settings.","")]=n[i]):(t[i.replace("ViewModel.","")]=null,t[i.replace("settings.","")]=null));return t}export function formatUtcTime(n=true){$("time").each(function(t,i){var u=$(i).data("utc-label"),r;u&&(r=new Date(u.replace(/-/g,"/")),n?$(i).html(r.toLocaleString()):$(i).html(r.toLocaleDateString()))})}